"use client"

import { useEffect, useState } from "react"
import { AdminLayout } from "@/components/admin-layout"
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card"
import { Input } from "@/components/ui/input"
import { Button } from "@/components/ui/button"

interface Rule {
  _id: string
  engine: "COMP" | "DOM" | "ARV" | "PROFIT"
  key: string
  value: number | boolean
  unit?: string
  description: string
  locked: boolean
}

export default function RulesPage() {
  const [rules, setRules] = useState<Rule[]>([])

  useEffect(() => {
    fetch("/api/rules")
      .then((res) => res.json())
      .then(setRules)
  }, [])

  const updateRule = async (id: string, value: any) => {
    await fetch(`/api/rules/${id}`, {
      method: "PATCH",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ value }),
    })
  }

  const grouped = rules.reduce((acc, rule) => {
    acc[rule.engine] = acc[rule.engine] || []
    acc[rule.engine].push(rule)
    return acc
  }, {} as Record<string, Rule[]>)

  return (
    <AdminLayout>
      <div className="p-8 space-y-6">
        <h1 className="text-4xl font-bold">Underwriting Rules (Phase 1)</h1>

        {Object.entries(grouped).map(([engine, rules]) => (
          <Card key={engine}>
            <CardHeader>
              <CardTitle>{engine} Rules</CardTitle>
            </CardHeader>
            <CardContent className="space-y-4">
              {rules.map((rule) => (
                <div key={rule._id} className="border p-4 rounded-lg space-y-2">
                  <div className="font-semibold">{rule.key}</div>
                  <p className="text-sm text-muted-foreground">{rule.description}</p>

                  <div className="flex gap-2 items-center">
                    <Input
                      type="number"
                      defaultValue={rule.value as number}
                      onBlur={(e) => updateRule(rule._id, Number(e.target.value))}
                      className="w-32"
                    />
                    <span className="text-sm">{rule.unit}</span>
                  </div>
                </div>
              ))}
            </CardContent>
          </Card>
        ))}
      </div>
    </AdminLayout>
  )
}
